@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Account recovery endpoint: accepts email and sends a reset link.
    The reset link will disable MFA, allowing the user to log in with just password.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Find user by email
    target_user = None
    for uid, user in users_db.items():
        if user['email'] == email:
            target_user = user
            break

    # Always return success to prevent email enumeration
    success_message = (
        'If an account with that email exists and has MFA enabled, '
        'a reset link has been sent to the registered email address.'
    )

    if not target_user:
        return jsonify({'message': success_message}), 200

    if not target_user['mfa_enabled']:
        return jsonify({'message': success_message}), 200

    # Generate a secure reset token
    reset_token = secrets.token_urlsafe(48)
    token_expiry = datetime.utcnow() + timedelta(hours=1)

    # Store the reset token
    mfa_reset_tokens[reset_token] = {
        'user_id': target_user['user_id'],
        'email': email,
        'created_at': datetime.utcnow().isoformat(),
        'expires_at': token_expiry.isoformat(),
        'used': False
    }

    # Build reset link
    reset_link = url_for('confirm_reset_mfa', token=reset_token, _external=True)

    # Send email with reset link
    email_subject = 'MFA Reset Request - Account Recovery'
    email_body = (
        f"Hello {target_user['username']},\n\n"
        f"We received a request to reset the Multi-Factor Authentication (MFA) on your account.\n\n"
        f"Click the following link to disable MFA and regain access to your account:\n"
        f"{reset_link}\n\n"
        f"This link will expire in 1 hour.\n\n"
        f"If you did not request this reset, please ignore this email and ensure your account is secure.\n\n"
        f"For security, after using this link, we recommend re-enabling MFA on your account.\n\n"
        f"- MFA Management System"
    )

    send_email(email, email_subject, email_body)

    return jsonify({'message': success_message}), 200


